import django
from django.conf import settings
settings.configure(
    DATABASES={'default': {'ENGINE': 'django.db.backends.sqlite3', 'NAME': ':memory:'}},
    INSTALLED_APPS=['django.contrib.contenttypes', 'django.contrib.auth'],
    USE_I18N=False,
)
django.setup()

from django.contrib import admin
from django.db import models

class MyModel(models.Model):
    myfield = models.ForeignKey('self', on_delete=models.CASCADE, blank=True, null=True)
    class Meta:
        app_label = 'test'

# Test 1: No custom empty_label set - should use default
class Admin1(admin.ModelAdmin):
    radio_fields = {'myfield': admin.HORIZONTAL}

ma1 = Admin1(MyModel, admin.AdminSite())
field1 = ma1.formfield_for_foreignkey(MyModel._meta.get_field('myfield'))
print('Test 1 (no custom empty_label):', repr(field1.empty_label))
assert field1.empty_label == '---------', f'Expected default None label, got {field1.empty_label!r}'

# Test 2: Custom empty_label set to None (should not override)
class Admin2(admin.ModelAdmin):
    radio_fields = {'myfield': admin.HORIZONTAL}
    def formfield_for_foreignkey(self, db_field, request=None, **kwargs):
        if db_field.name == 'myfield':
            kwargs['empty_label'] = None
        return super().formfield_for_foreignkey(db_field, request, **kwargs)

ma2 = Admin2(MyModel, admin.AdminSite())
field2 = ma2.formfield_for_foreignkey(MyModel._meta.get_field('myfield'))
print('Test 2 (empty_label=None):', repr(field2.empty_label))
# When empty_label is None and blank=True, the default is '---------'
# But if user explicitly sets None, we should respect that... 
# Actually with the fix, kwargs.get('empty_label') returns None, which is falsy, so it falls through to _('None')
# That's the same behavior as before for this edge case - which is fine

# Test 3: Custom empty_label set to empty string
class Admin3(admin.ModelAdmin):
    radio_fields = {'myfield': admin.HORIZONTAL}
    def formfield_for_foreignkey(self, db_field, request=None, **kwargs):
        if db_field.name == 'myfield':
            kwargs['empty_label'] = ''
        return super().formfield_for_foreignkey(db_field, request, **kwargs)

ma3 = Admin3(MyModel, admin.AdminSite())
field3 = ma3.formfield_for_foreignkey(MyModel._meta.get_field('myfield'))
print('Test 3 (empty_label=\"\"):', repr(field3.empty_label))
# Empty string is also falsy, so it falls through to default. This is acceptable.

print('All tests passed!')
"
"}

